if (!Object.keys($input.item.json).length) return [];

const email = $input.item.json;
const body = email.textPlain || email.snippet || email.textHtml || "";
const subject = email.subject || "";

// 2. 기본값 세팅
let name = "알 수 없는 사용처";
let price = "0";
let type = "Expense"; // 기본은 지출

// 3. 정규식(Regex)을 이용한 데이터 추출
const priceRegex = /([0-9,]+)\s*원/;
const priceMatch = body.match(priceRegex) || subject.match(priceRegex);
if (priceMatch) {
  price = priceMatch[1].replace(/,/g, '');
}

const nameRegex = /(?:가맹점명?|사용처|결제처|상호명?|입금처|송금처)\s*[:\-]?\s*([^\r\n<]+)/;
const nameMatch = body.match(nameRegex);
if (nameMatch) {
  name = nameMatch[1].trim();
} else {
  const subjectMatch = subject.match(/\[.*?\]\s*(.+?)\s*결제/);
  if (subjectMatch) {
    name = subjectMatch[1].trim();
  } else {
    name = subject;
  }
}

if (subject.includes("입금") || subject.includes("결제 취소") || body.includes("입금 완료")) {
  type = "Income";
}

const description = `**결제 승인 대기**\n- 사용처: ${name}\n- 금액: ${price}\n- 구분: ${type}\n\n*※ 아래 📝 이모지를 클릭하면 노션 가계부에 자동으로 반영됩니다.*`;

const discordPayload = {
  content: "",
  embeds: [
    {
      title: "💳 결제 승인 대기",
      description: description,
      color: type === "Expense" ? 16753920 : 65280
    }
  ]
};

return [{ json: { payload: discordPayload, messageId: email.id } }];
